NP_functionality.VERILOG_PROVIDED:
localparam BITSIZE_OUT = BITSIZE_IN + BANK_ID_SIZE;
`ifdef __M64
localparam OFFSET_BITSIZE = 64;
`else
localparam OFFSET_BITSIZE = 32;
`endif
if_utils #(index, OFFSET_BITSIZE) m_utils();
reg [BITSIZE_OUT-1:0] val;
wire [BITSIZE_OUT-1:0] val_next;

assign val_next = val;

always @(posedge clock) 
begin
  val <= val_next;
  if(setup_port)
  begin
    automatic ptr_t offset = m_utils.read();
    val <= offset[BITSIZE_OUT-1:0];
  end
end

generate 
genvar i;
  for(i = 0; i < CHANNEL_NUMBER; i = i + 1)
  begin
    if(BANK_ID_SIZE == 0)
    begin
      assign Mout_addr_ram_out[i*BITSIZE_OUT +: BITSIZE_OUT] = Mout_addr_ram[BITSIZE_IN +: BITSIZE_IN] + val;
    end
    else
    begin
      assign Mout_addr_ram_out[i*BITSIZE_OUT +: BITSIZE_OUT] = {Mout_addr_ram[(i+1)*BITSIZE_IN-1:i*BITSIZE_IN+EXTERNAL_BANK_ID_LAST_BIT],i[BANK_ID_SIZE-1:0],Mout_addr_ram[i*BITSIZE_IN+EXTERNAL_BANK_ID_LAST_BIT-1:i*BITSIZE_IN]} + val;
    end
  end
endgenerate


if_utils #(index, BITSIZE_m_axi_awaddr) m_utils();
reg [BITSIZE_m_axi_awaddr-1:0] val;
wire [BITSIZE_m_axi_awaddr-1:0] val_next;

assign val_next = val;

always @(posedge clock) 
begin
  val <= val_next;
  if(setup_port)
  begin
    val <= m_utils.read();
  end
end

generate
if(BANK_ID_SIZE == 0)
begin
  assign m_axi_awaddr = m_axi_awaddr_in + val;
  assign m_axi_araddr = m_axi_araddr_in + val;
end
else if(BITSIZE_m_axi_araddr_in == EXTERNAL_BANK_ID_LAST_BIT)
begin
  assign m_axi_awaddr = {ADAPTER_ID[BANK_ID_SIZE-1:0],m_axi_awaddr_in[EXTERNAL_BANK_ID_LAST_BIT-1:0]} + val;
  assign m_axi_araddr = {ADAPTER_ID[BANK_ID_SIZE-1:0],m_axi_araddr_in[EXTERNAL_BANK_ID_LAST_BIT-1:0]} + val;
end
else
begin
  assign m_axi_awaddr = {m_axi_awaddr_in[BITSIZE_m_axi_araddr_in-1:EXTERNAL_BANK_ID_LAST_BIT],ADAPTER_ID[BANK_ID_SIZE-1:0],m_axi_awaddr_in[EXTERNAL_BANK_ID_LAST_BIT-1:0]} + val;
  assign m_axi_araddr = {m_axi_araddr_in[BITSIZE_m_axi_awaddr_in-1:EXTERNAL_BANK_ID_LAST_BIT],ADAPTER_ID[BANK_ID_SIZE-1:0],m_axi_araddr_in[EXTERNAL_BANK_ID_LAST_BIT-1:0]} + val;
end
endgenerate

import "DPI-C" function int m_read (input shortint unsigned id, output logic [4095:0] data, input shortint unsigned bitsize, input ptr_t addr, input byte signed cmd);
import "DPI-C" function int m_write (input shortint unsigned id, input logic [4095:0] data, input shortint unsigned bitsize, input ptr_t addr, input byte signed cmd);
import "DPI-C" function int m_state (input shortint unsigned id, input int data);

function automatic integer log2;
  input integer value;
  `ifdef _SIM_HAVE_CLOG2
    log2 = $clog2(value);
  `else
    automatic integer temp_value = value-1;
    for (log2=0; temp_value > 0; log2=log2+1)
      temp_value = temp_value >> 1;
  `endif
endfunction

localparam BITSIZE_strobe=log2(BITSIZE_data) > 3 ? (1<<(log2(BITSIZE_data)-3)) : 1;

function automatic [BITSIZE_data-1:0] read();
  automatic reg [4095:0] _data = 0;
  void'(m_read(ID, _data, BITSIZE_data, 0, 0));
  return _data[BITSIZE_data-1:0];
endfunction

function automatic [BITSIZE_data-1:0] read_a(input ptr_t addr);
  automatic reg [4095:0] _data = 0;
  void'(m_read(ID, _data, BITSIZE_data, addr, 0));
  return _data[BITSIZE_data-1:0];
endfunction

function automatic [BITSIZE_data-1:0] read_i(output int info);
  automatic reg [4095:0] _data = 0;
  info = m_read(ID, _data, BITSIZE_data, 0, 0);
  return _data[BITSIZE_data-1:0];
endfunction

function automatic [BITSIZE_data-1:0] read_ai(input ptr_t addr, output int info);
  automatic reg [4095:0] _data = 0;
  info = m_read(ID, _data, BITSIZE_data, addr, 0);
  return _data[BITSIZE_data-1:0];
endfunction

function automatic [BITSIZE_data-1:0] pop(output int info);
  automatic reg [4095:0] _data = 0;
  info = m_read(ID, _data, BITSIZE_data, 0, 1);
  return _data[BITSIZE_data-1:0];
endfunction

function automatic int write(input logic [BITSIZE_data-1:0] data);
  automatic reg [4095:0] _data = 0;
  _data[BITSIZE_data-1:0] = data;
  return m_write(ID, _data, BITSIZE_data, 0, 0);
endfunction

function automatic int write_a(input logic [BITSIZE_data-1:0] data, input ptr_t addr);
  automatic reg [4095:0] _data = 0;
  _data[BITSIZE_data-1:0] = data;
  return m_write(ID, _data, BITSIZE_data, addr, 0);
endfunction

function automatic int write_sa(input logic [BITSIZE_data-1:0] data, input shortint unsigned bitsize, input ptr_t addr);
  automatic reg [4095:0] _data = 0;
  _data[BITSIZE_data-1:0] = data;
  return m_write(ID, _data, bitsize, addr, 0);
endfunction

function automatic int write_strobe(input logic [BITSIZE_data-1:0] data, input logic [BITSIZE_strobe-1:0] strobe, input ptr_t addr);
  automatic shortint unsigned size = 0;

  while(strobe != 0 && !strobe[0])
  begin
    addr = addr + 1;
    strobe = strobe >> 1;
  end
  while(strobe[0])
  begin
    size = size + 8;
    strobe = strobe >> 1;
  end
  if(strobe != 0)
  begin
    $display("Scattered strobe write operations not supported");
    $finish;
  end

  return write_sa(data, size, addr);
endfunction

function automatic int push(input logic [BITSIZE_data-1:0] data);
  automatic reg [4095:0] _data = 0;
  _data[BITSIZE_data-1:0] = data;
  return m_write(ID, _data, BITSIZE_data, 0, -1);
endfunction

function automatic int state(input int data);
  return m_state(ID, data);
endfunction

`ifdef VERILATOR
timeunit 1ps;
timeprecision 1ps;
`endif

import "DPI-C" function int unsigned m_next(input int unsigned state);
import "DPI-C" function int m_fini();

localparam [6:0] 
  STATE_READY   =7'b0000001,
  STATE_SETUP   =7'b0000010,
  STATE_RUNNING =7'b0000100,
  STATE_END     =7'b0001000,
  STATE_ERROR   =7'b0010000,
  STATE_ABORT   =7'b0100000,
  SIM_DONE      =7'b1000000;
reg [$bits(STATE_READY)-1:0] state, state_next, state_succ, state_succ_next;

reg rst, rst_next, setup, setup_next, start, start_next;
integer rst_count, rst_count_next;
time over_time;

initial
begin
  // Open file results will be written
  automatic integer res_file;
  res_file = $fopen(RESFILE, "w");
  if (res_file == 0)
  begin
    $display("ERROR - Error opening the res_file");
    $finish;// Terminate
  end
  $fwrite(res_file, "");
  $fclose(res_file);

  state = STATE_READY;
  state_next = STATE_READY;
  state_succ = STATE_READY;
  state_succ_next = STATE_READY;
  rst = RESET_ACTIVE;
  rst_next = RESET_ACTIVE;
  rst_count = RESET_CYCLES;
  rst_count_next = RESET_CYCLES;
  setup = 0;
  setup_next = 0;
  start = 0;
  start_next = 0;
  over_time = 0;

  $display("Results file: %s", RESFILE);
  $display("Reset active: %0s", RESET_ACTIVE ? "HIGH" : "LOW");
end

assign reset = rst;
assign setup_port = setup;
assign start_port = start;

always @(posedge clock)
begin
  state <= state_next;
  state_succ <= state_succ_next;
  rst <= rst_next;
  rst_count <= rst_count_next;
  setup <= setup_next;
  start <= start_next;
  case(state_next)
  STATE_READY:
    begin
      automatic integer unsigned next_state = m_next(STATE_READY);
      `ifndef NDEBUG
      $display("Sim: next state: %0d (retval: %0d)", next_state[$bits(state_succ)-1:0], next_state[15:8]);
      `endif
      state_succ <= next_state[$bits(state_succ)-1:0];
    end
  STATE_SETUP:
    begin
      automatic time start_time = $time + CLOCK_PERIOD;
      automatic time start_cycle = $rtoi($itor(start_time)/CLOCK_PERIOD);
      automatic integer res_file;
      if(setup_next)
      begin
        res_file = $fopen(RESFILE, "a");
        $fwrite(res_file, "%0d|", start_time);
        $fclose(res_file);
        `ifndef NDEBUG
        $display("Sim: Argument setup\nSim: Simulation started at cycle %0d", start_cycle);
        `endif
      end
      over_time <= start_cycle + MAX_SIM_CYCLES;
    end
  STATE_RUNNING:
    begin
      automatic time curr_cycle = $rtoi($itor($time)/CLOCK_PERIOD);
      if(curr_cycle >= over_time)
      begin
        automatic integer res_file;
        res_file = $fopen(RESFILE, "a");
        $fwrite(res_file, "X");
        $fclose(res_file);
        $display("Sim: Simulation exceeds %0d cycles", MAX_SIM_CYCLES);
        $finish;
      end
    end
  SIM_DONE:
    begin
      automatic time curr_time = $time;
      automatic time curr_cycle = $rtoi($itor(curr_time)/CLOCK_PERIOD);
      automatic integer res_file;
      res_file = $fopen(RESFILE, "a");
      $fwrite(res_file, "%0d,", curr_time);
      $fclose(res_file);
      `ifndef NDEBUG
      $display("Sim: DUT port writeback\nSim: Simulation ended at cycle %0d", curr_cycle);
      `endif
    end
  STATE_END:
    begin
      automatic integer r = m_fini();
      automatic integer res_file;
      res_file = $fopen(RESFILE, "a");
      $fwrite(res_file, "\n%0d\n", r[15:8]);
      $fclose(res_file);
      $display("Sim: Driver terminated with code: %0d", r[15:8]);
      $finish;
    end
  STATE_ABORT:
    begin
      automatic integer r = m_fini();
      automatic integer res_file;
      res_file = $fopen(RESFILE, "a");
      $fwrite(res_file, "\nA\n");
      $fclose(res_file);
      $display("Sim: Driver aborted");
      $finish;
    end
  default:
    begin
    end
  endcase
end

always @(*)
begin
  rst_next = rst;
  rst_count_next = rst_count;
  setup_next = setup;
  start_next = start;
  state_next = state;
  state_succ_next = state_succ;
  case(state)
  STATE_READY:
    begin
      state_next = state_succ;
      if(state_succ == STATE_SETUP)
      begin
        if(RESET_ALWAYS || rst_count > 0)
        begin
          rst_next = RESET_ACTIVE;
          rst_count_next = RESET_CYCLES;
        end
        else
        begin
          rst_count_next = 1;
        end
      end
    end
  STATE_SETUP:
    begin
      if(rst_count > 1)
      begin
        setup_next = rst_count == 0;
        rst_next = RESET_ACTIVE;
        rst_count_next = rst_count - 1;
      end
      else if(rst_count == 1)
      begin
        setup_next = 1;
        rst_next = ~RESET_ACTIVE;
        rst_count_next = 0;
      end
      else
      begin
        state_next = STATE_RUNNING;
        setup_next = 0;
        start_next = 1;
      end
    end
  STATE_RUNNING:
    begin
      start_next = 0;
      if(done_port)
      begin
        state_next = SIM_DONE;
      end
    end
  SIM_DONE:
    begin
      // A clock cycle must pass to allow interface modules 
      // finalization operations
      state_next = STATE_READY;
    end
  STATE_END:
    begin
    end
  STATE_ABORT:
    begin
    end
  default:
    begin
      state_next = STATE_READY;
    end
  endcase
end

function automatic integer log2;
  input integer value;
  `ifdef _SIM_HAVE_CLOG2
    log2 = $clog2(value);
  `else
    automatic integer temp_value = value-1;
    for (log2=0; temp_value > 0; log2=log2+1)
      temp_value = temp_value >> 1;
  `endif
endfunction

localparam MEM_DELAY_MAX= MEM_DELAY_READ > MEM_DELAY_WRITE ? MEM_DELAY_READ : MEM_DELAY_WRITE,
  ACTIVE_READ= MEM_DELAY_READ > 1 ? (MEM_DELAY_READ-2) : 0,
  ACTIVE_WRITE= MEM_DELAY_WRITE > 1 ? (MEM_DELAY_WRITE-2) : 0,
  CHANNELS_NUMBER=BITSIZE_Mout_oe_ram,
  BITSIZE_oe=1,
  BITSIZE_we=1,
  BITSIZE_addr=BITSIZE_Mout_addr_ram/CHANNELS_NUMBER,
  BITSIZE_Wsize=BITSIZE_Mout_data_ram_size/CHANNELS_NUMBER,
  BITSIZE_Wdata=BITSIZE_Mout_Wdata_ram/CHANNELS_NUMBER,
  BITSIZE_Rdata=BITSIZE_M_Rdata_ram/CHANNELS_NUMBER,
  BITSIZE_tag=BITSIZE_Mout_tag/CHANNELS_NUMBER,
  BITSIZE_item=BITSIZE_tag+BITSIZE_Wdata+BITSIZE_Wsize+BITSIZE_addr+BITSIZE_we+BITSIZE_oe,
  OFFSET_oe=0,
  OFFSET_we=OFFSET_oe+BITSIZE_oe,
  OFFSET_addr=OFFSET_we+BITSIZE_we,
  OFFSET_Wsize=OFFSET_addr+BITSIZE_addr,
  OFFSET_Wdata=OFFSET_Wsize+BITSIZE_Wsize,
  OFFSET_tag = OFFSET_Wdata+BITSIZE_Wdata,
  BITSIZE_S_Rdata=BITSIZE_Sout_Rdata_ram/BITSIZE_S_oe_ram,
  BITSIZE_S_ready=1,
  SLAVE_VALID=BITSIZE_Mout_oe_ram == BITSIZE_S_oe_ram,
  QUEUE_BITSIZE=QUEUE_SIZE > 1 ? log2(QUEUE_SIZE) : 1;

genvar i;
integer dump_file;
wire [BITSIZE_M_Rdata_ram-1:0] _M_Rdata_ram;

assign S_oe_ram = Mout_oe_ram;
assign S_we_ram = Mout_we_ram;
assign S_addr_ram = Mout_addr_ram;
assign S_data_ram_size = Mout_data_ram_size;
assign S_Wdata_ram = Mout_Wdata_ram;
assign M_Rdata_ram = _M_Rdata_ram;

generate
  if(MEM_DUMP)
  begin
    initial
    begin
      dump_file = $fopen(MEM_DUMP_FILE, "w");
      $fwrite(dump_file, "Channel,Operation,Address,Bitwidth,Data\n");
    end

    always@(posedge clock)
    begin
      if(done_port)
      begin
        $fflush(dump_file);
      end
    end
  end
endgenerate

if_utils #(index, BITSIZE_Rdata) m_utils();

generate
  for(i = 0; i < CHANNELS_NUMBER; i = i + 1)
  begin : channel
    wire [BITSIZE_item-1:0] new_elem;
    reg [MEM_DELAY_MAX*BITSIZE_item-1:0] queue;
    wire [MEM_DELAY_MAX*BITSIZE_item-1:0] queue_next;
    wire [BITSIZE_oe-1:0] oe;
    wire [BITSIZE_we-1:0] we;
    ptr_t Waddr, Raddr;
    shortint unsigned Wsize;
    wire [BITSIZE_Wdata-1:0] Wdata;
    reg Wready, Rready;
    reg [BITSIZE_Rdata-1:0] Rdata;

    reg [QUEUE_BITSIZE-1:0] queue_counter;
    wire [QUEUE_BITSIZE-1:0] queue_counter_next;

    assign new_elem = Mout_back_pressure[i] ? {BITSIZE_item{1'b0}} : {Mout_tag[BITSIZE_tag*i+:BITSIZE_tag],Mout_Wdata_ram[BITSIZE_Wdata*i+:BITSIZE_Wdata],Mout_data_ram_size[BITSIZE_Wsize*i+:BITSIZE_Wsize],Mout_addr_ram[BITSIZE_addr*i+:BITSIZE_addr],Mout_we_ram[BITSIZE_we*i+:BITSIZE_we],Mout_oe_ram[BITSIZE_oe*i+:BITSIZE_oe]};
    assign queue_next = M_back_pressure[i] ? queue[MEM_DELAY_MAX*BITSIZE_item-1:0] : {queue[(MEM_DELAY_MAX-1)*BITSIZE_item-1:0],new_elem};

    always@(posedge clock)
    begin
      if(1RESET_VALUE)
      begin
        queue <= 0;
      end
      else
      begin
        queue <= queue_next;
      end
    end

    assign oe = queue_next[ACTIVE_READ*BITSIZE_item+OFFSET_oe+:BITSIZE_oe];
    assign Raddr = queue_next[ACTIVE_READ*BITSIZE_item+OFFSET_addr+:BITSIZE_addr];
    assign _M_Rdata_ram[BITSIZE_Rdata*i+:BITSIZE_Rdata] = Rdata | (Sout_Rdata_ram[BITSIZE_S_Rdata*i*SLAVE_VALID+:BITSIZE_S_Rdata] & {BITSIZE_S_Rdata{Sout_DataRdy[BITSIZE_S_ready*i*SLAVE_VALID+:BITSIZE_S_ready] === 1'b1}});

    always@(posedge clock)
    begin : read_channel
      automatic reg [BITSIZE_Rdata-1:0] data;
      Rready <= 0;
      Rdata <= 0;
      if(oe && base_addr <= Raddr)
      begin
        data = m_utils.read_a(Raddr);
        Rdata <= data;
        Rready <= 1;
        if(MEM_DUMP)
        begin
          $fwrite(dump_file, "%0d,r,%0X,%0d,%0X\n", i, Raddr, BITSIZE_Rdata, data);
        end
      end
    end

    assign we = queue_next[ACTIVE_WRITE*BITSIZE_item+OFFSET_we+:BITSIZE_we];
    assign Waddr = queue_next[ACTIVE_WRITE*BITSIZE_item+OFFSET_addr+:BITSIZE_addr];
    assign Wsize = {{16-BITSIZE_Wsize{1'b0}}, queue_next[ACTIVE_WRITE*BITSIZE_item+OFFSET_Wsize+:BITSIZE_Wsize]};
    assign Wdata = queue_next[ACTIVE_WRITE*BITSIZE_item+OFFSET_Wdata+:BITSIZE_Wdata];

    always@(posedge clock)
    begin : write_channel
      Wready <= 0;
      if(we && base_addr <= Waddr)
      begin
        void'(m_utils.write_sa(Wdata, Wsize, Waddr));
        Wready <= 1;
        if(MEM_DUMP)
        begin
          $fwrite(dump_file, "%0d,w,%0X,%0d,%0X\n", i, Waddr, Wsize, Wdata);
        end
      end
    end

    if(EMULATE_BRAM)
    begin
      assign Mout_back_pressure[i] = 0; // No back pressure with BRAM
    end
    else
    begin
      wire _M_DataRdy, _M_DataRdy_wire;
      assign M_DataRdy[i] = _M_DataRdy;
      assign _M_DataRdy = Wready | Rready | (Sout_DataRdy[BITSIZE_S_ready*i*SLAVE_VALID+:BITSIZE_S_ready] === 1'b1);
      assign _M_DataRdy_wire = Wready | Rready; // Used to update at posedge clock of the queue_counter;

      always @(posedge clock)
      begin
        if(1RESET_VALUE)
        begin
          queue_counter <= 0;
        end
        else
        begin
          queue_counter <= queue_counter_next;
        end
      end

      if(QUEUE_SIZE > 1)
      begin
        assign queue_counter_next = queue_counter + (((Mout_we_ram[i] || Mout_oe_ram[i]) && !Mout_back_pressure[i] && base_addr <= Mout_addr_ram[i*BITSIZE_addr +: BITSIZE_addr]) && (queue_counter == 0 ? 1 : (queue_counter  - (_M_DataRdy_wire && !M_back_pressure[i])) < (QUEUE_SIZE - 1))) - (_M_DataRdy_wire && !M_back_pressure[i]);
      end
      else 
      begin
        assign queue_counter_next = ((Mout_we_ram[i] || Mout_oe_ram[i]) && !Mout_back_pressure[i] && base_addr <= Mout_addr_ram[i*BITSIZE_addr +: BITSIZE_addr]) || (queue_counter && !_M_DataRdy_wire && !M_back_pressure[i]);
      end

      if(QUEUE_SIZE > 1)
      begin
        assign Mout_back_pressure[i] = M_back_pressure[i] || (queue_counter == 0 ? 0 : (queue_counter - _M_DataRdy_wire) == (QUEUE_SIZE - 1));
      end
      else 
      begin
        assign Mout_back_pressure[i] = M_back_pressure[i] || (queue_counter && !_M_DataRdy_wire);
      end

      reg [BITSIZE_tag-1:0] Rtag, Wtag;
      wire [BITSIZE_tag-1:0] _M_tag;
      assign _M_tag = Wtag | Rtag;
      assign M_tag[BITSIZE_tag*i+:BITSIZE_tag] = _M_tag;

      always@(posedge clock)
      begin 
        Rtag <= 0;
        if(oe && base_addr <= Raddr)
        begin
          Rtag <= queue_next[ACTIVE_READ*BITSIZE_item+OFFSET_tag+:BITSIZE_tag];
        end
      end

      always@(posedge clock)
      begin 
        Wtag <= 0;
        if(we && base_addr <= Waddr)
        begin
          Wtag <= queue_next[ACTIVE_WRITE*BITSIZE_item+OFFSET_tag+:BITSIZE_tag];
        end
      end
    end

    always @(posedge clock)
    begin
      if (we & oe)
      begin
        $display("ERROR - Mout_we_ram and Mout_oe_ram both enabled on channel %0d!", i);
        $finish;
      end
    end
  end
endgenerate

localparam BITSIZE_data=BITSIZE_rdata,
  BITSIZE_counter=32,
  BITSIZE_burst=BITSIZE_arburst,
  BITSIZE_len=BITSIZE_arlen,
  BITSIZE_delay=32,
  BITSIZE_size=BITSIZE_arsize,
  BITSIZE_addr=BITSIZE_araddr,
  BITSIZE_id=BITSIZE_arid,
  OFFSET_delay=0,
  OFFSET_counter=OFFSET_delay+BITSIZE_delay,
  OFFSET_burst=OFFSET_counter+BITSIZE_counter,
  OFFSET_len=OFFSET_burst+BITSIZE_burst,
  OFFSET_size=OFFSET_len+BITSIZE_len,
  OFFSET_addr=OFFSET_size+BITSIZE_size,
  OFFSET_id=OFFSET_addr+BITSIZE_addr,
  OFFSET_data=OFFSET_id+BITSIZE_id,
  OFFSET_wstrb=OFFSET_data+BITSIZE_data,
  BITSIZE_aritem=BITSIZE_id+BITSIZE_addr+BITSIZE_size+BITSIZE_len+BITSIZE_burst+BITSIZE_counter+BITSIZE_delay,
  BITSIZE_awitem=BITSIZE_wstrb+BITSIZE_data+BITSIZE_id+BITSIZE_addr+BITSIZE_size+BITSIZE_len+BITSIZE_burst+BITSIZE_counter+BITSIZE_delay;

reg [QUEUE_SIZE*BITSIZE_aritem-1:0] arqueue;
reg [QUEUE_SIZE*BITSIZE_aritem-1:0] next_arqueue;
reg [QUEUE_SIZE*BITSIZE_awitem-1:0] awqueue; 
reg [QUEUE_SIZE*BITSIZE_awitem-1:0] next_awqueue;
reg [31:0] test_addr;
reg [31:0] test_wstrb;
reg [31:0] test_data;
reg [31:0] test_addr_read;
integer arqueue_size, next_arqueue_size;
integer awqueue_size, next_awqueue_size;

reg [BITSIZE_id-1:0] awid_reg;
reg [BITSIZE_addr-1:0] awaddr_reg;
reg [BITSIZE_size-1:0] awsize_reg;
reg [BITSIZE_len-1:0] awlen_reg; 
reg [BITSIZE_burst-1:0] awburst_reg;
reg [BITSIZE_counter-1:0] counter_reg, counter_next;
reg write_done;
reg wlast_reg, wlast_next;

initial
begin
  arqueue = 0;
  arqueue_size = 0;
  next_arqueue = 0;
  next_arqueue_size = 0;
  awqueue = 0;
  awqueue_size = 0;
  next_awqueue = 0;
  next_awqueue_size = 0;
  awid_reg = 0;
  awaddr_reg = 0;
  awsize_reg = 0;
  awlen_reg = 0;
  awburst_reg = 0;
end

if_utils #(index, BITSIZE_data) m_utils();

reg awready_reg, wready_reg, bvalid_reg, arready_reg, rlast_reg, rvalid_reg;
reg [BITSIZE_bid-1:0] bid_reg;
reg [BITSIZE_bresp-1:0] bresp_reg;
reg [BITSIZE_buser-1:0] buser_reg;
reg [BITSIZE_rid-1:0] rid_reg;
reg [BITSIZE_rdata-1:0] rdata_reg;
reg [BITSIZE_rresp-1:0] rresp_reg;
reg [BITSIZE_ruser-1:0] ruser_reg;

assign awready = awready_reg;
assign wready = wready_reg;
assign bid = bid_reg;
assign bresp = bresp_reg;
assign buser = buser_reg;
assign bvalid = bvalid_reg;
assign arready = arready_reg;
assign rid = rid_reg;
assign rdata = rdata_reg;
assign rresp = rresp_reg;
assign rlast = rlast_reg;
assign ruser = ruser_reg;
assign rvalid = rvalid_reg;

initial
begin
  awready_reg = 0;
  wready_reg = 0;
  bid_reg = 0;
  bresp_reg = 0;
  buser_reg = 0;
  bvalid_reg = 0;
  arready_reg = 0;
  rid_reg = 0;
  rdata_reg = 0;
  rresp_reg = 0;
  rlast_reg = 0;
  ruser_reg = 0;
  rvalid_reg= 0;
end

// Combinatorial logic for read transactions
always@(*)
begin: read_comb
  automatic int next_arqueue_size_increase, next_arqueue_size_decrease;
  automatic integer unsigned i;
  next_arqueue = arqueue;
  next_arqueue_size_increase = 0;
  next_arqueue_size_decrease = 0;
  for(i = 0; i < QUEUE_SIZE; i = i + 1)
  begin
    if(arqueue[i*BITSIZE_aritem+OFFSET_delay+:BITSIZE_delay] > 1)
    begin
      next_arqueue[i*BITSIZE_aritem+OFFSET_delay+:BITSIZE_delay] = arqueue[i*BITSIZE_aritem+OFFSET_delay+:BITSIZE_delay] - 1;
    end
  end
  if(arqueue_size > 0 && arqueue[OFFSET_counter+:BITSIZE_counter] >= (arqueue[OFFSET_len+:BITSIZE_len] + 1) && rready && rvalid_reg)
  begin
    for(i = 1; i < QUEUE_SIZE; i = i + 1)
    begin
      next_arqueue[(i-1)*BITSIZE_aritem+:BITSIZE_aritem] = next_arqueue[i*BITSIZE_aritem+:BITSIZE_aritem];
    end
    next_arqueue_size_decrease = 1;
  end
  if(arvalid && arready_reg)  // Valid and ready -> accept new transaction
  begin
    next_arqueue[(arqueue_size - next_arqueue_size_decrease)*BITSIZE_aritem +:BITSIZE_aritem] = {arid, araddr, arsize, arlen, arburst, {BITSIZE_counter{1'b0}}, ({BITSIZE_delay{1'b0}} + READ_DELAY)}; // size of parameter is implementation dependent
    next_arqueue_size_increase = 1;
  end
  next_arqueue_size = arqueue_size + next_arqueue_size_increase - next_arqueue_size_decrease;
  if(next_arqueue_size > 0 && (next_arqueue[OFFSET_delay+:BITSIZE_delay] == 1) && (next_arqueue[OFFSET_counter+:BITSIZE_counter] < (next_arqueue[OFFSET_len+:BITSIZE_len] + 1)))
  begin
    next_arqueue[OFFSET_counter+:BITSIZE_counter] = next_arqueue[OFFSET_counter+:BITSIZE_counter] + 1;
  end
end

// Combinatorial logic for write transactions
always@(*) 
begin: write_comb
  automatic int next_awqueue_size_increase, next_awqueue_size_decrease;
  automatic integer i;
  automatic reg [BITSIZE_counter-1:0] counter;
  next_awqueue = awqueue;
  next_awqueue_size_increase = 0;
  next_awqueue_size_decrease = 0;
  wlast_next = wlast_reg;
  counter_next = counter_reg; 
  for(i = 0; i < QUEUE_SIZE; i = i + 1)
  begin
    if(awqueue[i*BITSIZE_awitem+OFFSET_delay+:BITSIZE_delay] > 1)
    begin
      next_awqueue[i*BITSIZE_awitem+OFFSET_delay+:BITSIZE_delay] = awqueue[i*BITSIZE_awitem+OFFSET_delay+:BITSIZE_delay] - 1;
    end
  end
  if(write_done && awqueue_size > 0 && bready)
  begin
    for(i = 1; i < QUEUE_SIZE; i = i + 1)
    begin
      next_awqueue[(i-1)*BITSIZE_awitem+:BITSIZE_awitem] = next_awqueue[i*BITSIZE_awitem+:BITSIZE_awitem];
    end
    next_awqueue_size_decrease = 1;
  end
  if(awvalid && awready_reg && wready_reg && wvalid) // Valid and ready -> accept new transaction and save data
  begin
    next_awqueue[(awqueue_size-next_awqueue_size_decrease)*BITSIZE_awitem+:BITSIZE_awitem] = {wstrb, wdata, awid, awaddr, awsize, awlen, awburst, {BITSIZE_counter{1'b0}}, ({BITSIZE_delay{1'b0}} + WRITE_DELAY)};
    next_awqueue_size_increase = 1;
  end
  else if(awvalid && awready_reg && wlast_reg)
  begin
    awid_reg = awid;
    awaddr_reg = awaddr;
    awsize_reg = awsize;
    awlen_reg = awlen; 
    awburst_reg = awburst;
    counter_next = 0;
    wlast_next = 0;
  end
  else if(wready_reg && wvalid)
  begin
    next_awqueue[(awqueue_size-next_awqueue_size_decrease)*BITSIZE_awitem+:BITSIZE_awitem] = {wstrb, wdata, awid_reg, awaddr_reg, awsize_reg, awlen_reg, awburst_reg, counter_reg, ({BITSIZE_delay{1'b0}} + WRITE_DELAY)};
    next_awqueue_size_increase = 1;
    counter_next = counter_reg + 1;
  end
  next_awqueue_size = awqueue_size + next_awqueue_size_increase - next_awqueue_size_decrease;
end

always@(posedge clock)
begin
   if(1RESET_VALUE)
   begin
    arready_reg <= 0;
    awready_reg <= 0;
    wready_reg <= 0;
    wlast_reg <= 1;
    counter_reg <= 0;
   end
   else
   begin
    arready_reg <= (next_arqueue_size - (next_arqueue_size > 0 && next_arqueue[OFFSET_delay+:BITSIZE_delay] == 1 && next_arqueue[OFFSET_counter+:BITSIZE_counter] >= next_arqueue[OFFSET_len+:BITSIZE_len])) < (QUEUE_SIZE - 1);  //Ready if next_queue_size - rlast_reg < QUEUE_SIZE
    awready_reg <= (wlast_next || wlast) && ((next_awqueue_size - (next_awqueue_size > 0 && next_awqueue[OFFSET_delay+:BITSIZE_delay] == 1)) < (QUEUE_SIZE - 1)); // ready if next_queue_size - bvalid_reg < QUEUE_SIZE
    wready_reg <= (next_awqueue_size - (next_awqueue_size > 0 && next_awqueue[OFFSET_delay+:BITSIZE_delay] == 1)) < (QUEUE_SIZE - 1); 
    wlast_reg <= wlast_next || wlast;
    counter_reg <= counter_next;
   end
end

always@(posedge clock)
begin
   if(1RESET_VALUE)
   begin
    rvalid_reg <= 0;
    bvalid_reg <= 0;
   end
   else
   begin
    rvalid_reg <= (next_arqueue_size > 0 && next_arqueue[OFFSET_delay+:BITSIZE_delay] == 1); // if at posedge_clock delay is 1 I have to perfrom the operation in this cycle
    bvalid_reg <= (next_awqueue_size > 0 && next_awqueue[OFFSET_delay+:BITSIZE_delay] == 1 && next_awqueue[OFFSET_counter+:BITSIZE_counter] == (next_awqueue[OFFSET_len+:BITSIZE_len])); // if at posedge_clock delay is 1 I have to perfrom the last operation in this cycle
   end
end

always@(posedge clock)
begin
   if(1RESET_VALUE)
   begin
    arqueue <= 0;
    arqueue_size <= 0;
    awqueue <= 0;
    awqueue_size <= 0;
   end
   else
   begin
    arqueue <= next_arqueue;
    arqueue_size <= next_arqueue_size;
    awqueue <= next_awqueue;
    awqueue_size <= next_awqueue_size;
   end
end

// Sequential logic for read transactions
always@(posedge clock)
begin : read_seq
  automatic ptr_t currAddr;
  automatic ptr_t endAddr;
  rlast_reg <= 0;
  test_addr_read <= 0;
  if(next_arqueue_size > 0 && next_arqueue[OFFSET_delay+:BITSIZE_delay] == 1)
  begin
    if(next_arqueue[OFFSET_burst+:BITSIZE_burst] == 2'b00)
    begin
      currAddr = next_arqueue[OFFSET_addr+:BITSIZE_addr];
    end
    else if(next_arqueue[OFFSET_burst+:BITSIZE_burst] == 2'b01)
    begin
      currAddr = next_arqueue[OFFSET_addr+:BITSIZE_addr] + (next_arqueue[OFFSET_counter+:BITSIZE_counter] - 1) * (1 << next_arqueue[OFFSET_size+:BITSIZE_size]);
    end
    else
    begin
      $display("Unsupported burst type: %0d", next_arqueue[OFFSET_burst+:BITSIZE_burst]);
      $finish;
    end
    test_addr_read <= currAddr;
    rid_reg <= next_arqueue[OFFSET_id+:BITSIZE_id];
    rdata_reg <= m_utils.read_a(currAddr);
    if(next_arqueue[OFFSET_counter+:BITSIZE_counter] >= (next_arqueue[OFFSET_len+:BITSIZE_len] + 1))
    begin
      rlast_reg <= 1;
    end
  end
end

// Sequential logic for write transactions
always@(posedge clock)
begin: write_seq
  automatic ptr_t currAddr;
  automatic ptr_t endAddr;
  test_wstrb <=0;
  test_addr <= 0;
  test_data <= 0;
  write_done <= 0;
  if(next_awqueue_size > 0 && next_awqueue[OFFSET_delay+:BITSIZE_delay] == 1) // Performs the first write of the queue
  begin
    if(next_awqueue[OFFSET_burst+:BITSIZE_burst] == 2'b00)
    begin
      currAddr = next_awqueue[OFFSET_addr+:BITSIZE_addr];
    end
    else if(next_awqueue[OFFSET_burst+:BITSIZE_burst] == 2'b01)
    begin
      currAddr = next_awqueue[OFFSET_addr+:BITSIZE_addr] + next_awqueue[OFFSET_counter+:BITSIZE_counter] * (1 << next_awqueue[OFFSET_size+:BITSIZE_size]);
    end
    else
    begin
      $display("Unsupported burst type: %0d", next_arqueue[OFFSET_burst+:BITSIZE_burst]);
      $finish;
    end
    test_wstrb <= next_awqueue[OFFSET_wstrb+:BITSIZE_wstrb];
    test_addr <= currAddr;
    test_data <= next_awqueue[OFFSET_data+:BITSIZE_data];
    bid_reg <= next_awqueue[OFFSET_id+:BITSIZE_id];
    write_done <= 1;
    void'(m_utils.write_strobe(next_awqueue[OFFSET_data+:BITSIZE_data], next_awqueue[OFFSET_wstrb+:BITSIZE_wstrb], currAddr));
  end
end

localparam MEM_DELAY_MAX= MEM_DELAY_READ > MEM_DELAY_WRITE ? MEM_DELAY_READ : MEM_DELAY_WRITE,
  BITSIZE_item=BITSIZE_dat_im+1+1;
reg cyc, stb, we, stall, ack;
reg [BITSIZE_addr_om-1:0] addr;
reg [BITSIZE_dat_om-1:0] Wdata;
reg [7:0] size;
reg [BITSIZE_dat_im-1:0] Rdata;

reg [MEM_DELAY_MAX*BITSIZE_item-1:0] queue, queue_next;

if_utils #(index, BITSIZE_dat_im) m_utils();

initial
begin
  stall = 0;
  ack = 0;
  Rdata = 0;
  queue = 0;
end

assign cyc_is = 0;
assign stb_is = 0;
assign addr_is = 0;
assign dat_is = 0;
assign sel_is = 0;

assign cyc = cyc_om;
assign stb = stb_om;
assign we = we_om;
assign addr = addr_om;
assign Wdata = dat_om;
assign size = sel_om;
assign stall_im = stall; // & cyc
assign ack_im = ack; // & cyc
assign dat_im = Rdata; // & {BITSIZE_dat_im{cyc}};

always @(posedge clock)
begin
  automatic reg w_ack = queue_next[(MEM_DELAY_WRITE-1)*BITSIZE_item] & queue_next[(MEM_DELAY_WRITE-1)*BITSIZE_item+1];
  automatic reg r_ack = queue_next[(MEM_DELAY_READ-1)*BITSIZE_item] & ~queue_next[(MEM_DELAY_READ-1)*BITSIZE_item+1];
  ack <= w_ack | r_ack;
  Rdata <= queue_next[(MEM_DELAY_READ-1)*BITSIZE_item+2 +:BITSIZE_dat_im];
  queue <= queue_next;
end

always @(*)
begin
  queue_next = {queue[(MEM_DELAY_MAX-1)*BITSIZE_item-1:0], {BITSIZE_dat_im{1'b0}}, 1'b0, 1'b0};
  if(cyc & stb)
  begin
    queue_next[1:0] = {we, 1'b1};
  end
end

always @(negedge clock)
begin
  if(queue_next[0])
  begin
    automatic ptr_t ptr_addr = addr;
    if(queue_next[1])
    begin
      void'(m_utils.write_strobe(Wdata, sel_om, ptr_addr));
    end
    else
    begin
      queue_next[BITSIZE_item-1:2] <= m_utils.read_a(ptr_addr);
    end
  end
end

if_utils #(index, BITSIZE_val_port) m_utils();
reg [BITSIZE_val_port-1:0] val;
wire [BITSIZE_val_port-1:0] val_next;

initial val = 0;

assign val_port = val;
assign val_next = val;

always @(posedge clock) 
begin
  val <= val_next;
  if(setup_port)
  begin
    val <= m_utils.read();
  end
end

localparam HOLD=PIPELINED ? 1'b0 : 1'b1,
  CHANNELS_NUMBER=BITSIZE_S_we_ram,
  BITSIZE_we=1,
  BITSIZE_addr=BITSIZE_S_addr_ram/CHANNELS_NUMBER,
  BITSIZE_Wsize=BITSIZE_S_data_ram_size/CHANNELS_NUMBER,
  BITSIZE_Wdata=BITSIZE_S_Wdata_ram/CHANNELS_NUMBER,
  BITSIZE_ready=1;
reg [bitsize-1:0] val, val_next;
reg we, we_next, waiting, waiting_next, start, start_next;
reg [BITSIZE_addr-1:0] addr, addr_next;
reg [BITSIZE_Wdata-1:0] data, data_next;
reg [BITSIZE_Wsize-1:0] data_size, data_size_next;
wire rdy;

if_utils #(index, bitsize) m_utils();

assign rdy = Sout_DataRdy[0];

assign S_oe_ram = {BITSIZE_S_oe_ram{1'b0}};
assign S_we_ram = {{BITSIZE_S_we_ram-BITSIZE_we{1'b0}}, we_next};
assign S_addr_ram = {{BITSIZE_S_addr_ram-BITSIZE_addr{1'b0}}, addr_next};
assign S_Wdata_ram = {{BITSIZE_S_Wdata_ram-BITSIZE_Wdata{1'b0}}, data_next};
assign S_data_ram_size = {{BITSIZE_S_data_ram_size-BITSIZE_Wsize{1'b0}}, data_size_next};
assign start_port = start;

always @(posedge clock) 
begin
  val <= val_next;
  we <= we_next;
  addr <= addr_next;
  data <= data_next;
  data_size <= data_size_next;
  waiting <= waiting_next;
  start <= start_next;
  if(1RESET_VALUE)
  begin
    val <= 0;
    we <= 0;
    addr <= 0;
    data <= 0;
    data_size <= 0;
    waiting <= 0;
    start <= 0;
  end
  else if(setup_port)
  begin
    val <= m_utils.read();
  end
end

always @(*)
begin
  val_next = val;
  we_next = we & HOLD & waiting & ~rdy;
  addr_next = addr & {BITSIZE_addr{HOLD & waiting & ~rdy}};
  data_next = data & {BITSIZE_Wdata{HOLD & waiting & ~rdy}};
  data_size_next = data_size & {BITSIZE_Wsize{HOLD & waiting & ~rdy}};
  waiting_next = waiting & ~rdy;
  start_next = waiting & rdy;
  if(i_start_port)
  begin
    we_next = 1;
    addr_next = tgt_addr;
    data_next = {{BITSIZE_Wdata-bitsize{1'b0}}, val};
    data_size_next = bitsize;
    waiting_next = ~rdy;
    start_next = rdy;
  end
end

localparam HOLD=PIPELINED ? 1'b0 : 1'b1,
  CHANNELS_NUMBER=BITSIZE_S_oe_ram,
  BITSIZE_oe=1,
  BITSIZE_addr=BITSIZE_S_addr_ram/CHANNELS_NUMBER,
  BITSIZE_ready=1,
  BITSIZE_Rdata=BITSIZE_Sout_Rdata_ram/CHANNELS_NUMBER;
reg oe, oe_next, waiting, waiting_next, done, done_next;
reg [BITSIZE_addr-1:0] addr, addr_next;
wire rdy;

if_utils #(index, bitsize) m_utils();

assign rdy = Sout_DataRdy[0];

assign S_oe_ram = {{BITSIZE_S_oe_ram-BITSIZE_oe{1'b0}}, oe_next};
assign S_we_ram = {BITSIZE_S_we_ram{1'b0}};
assign S_addr_ram = {{BITSIZE_S_addr_ram-BITSIZE_addr{1'b0}}, addr_next};
assign S_Wdata_ram = {BITSIZE_S_Wdata_ram{1'b0}};
assign S_data_ram_size = {BITSIZE_S_data_ram_size{1'b0}};
assign start_port = i_start_port;
assign done_port = done;

always @(posedge clock) 
begin
  oe <= oe_next;
  addr <= addr_next;
  waiting <= waiting_next;
  done <= done_next;
  if(1RESET_VALUE)
  begin
    oe <= 0;
    addr <= 0;
    waiting <= 0;
    done <= 0;
  end
  else if(done_next)
  begin
    void'(m_utils.write(Sout_Rdata_ram[BITSIZE_Rdata-1:0]));
  end
end

always @(*)
begin
  oe_next = oe & HOLD & waiting & ~rdy;
  addr_next = addr & {BITSIZE_addr{HOLD & waiting & ~rdy}};
  waiting_next = waiting & ~rdy;
  done_next = waiting & rdy;
  if(i_done_port)
  begin
    oe_next = 1;
    addr_next = tgt_addr;
    waiting_next = ~rdy;
    done_next = rdy;
  end
end

localparam HOLD=PIPELINED ? 1'b0 : 1'b1,
  CHANNELS_NUMBER=BITSIZE_S_we_ram,
  BITSIZE_we=1,
  BITSIZE_addr=BITSIZE_S_addr_ram/CHANNELS_NUMBER,
  BITSIZE_Wsize=BITSIZE_S_data_ram_size/CHANNELS_NUMBER,
