assign S_we_ram = {{BITSIZE_S_we_ram-BITSIZE_we{1'b0}}, we_next};
assign S_addr_ram = {{BITSIZE_S_addr_ram-BITSIZE_addr{1'b0}}, addr_next};
assign S_Wdata_ram = {{BITSIZE_S_Wdata_ram-BITSIZE_Wdata{1'b0}}, data_next};
assign S_data_ram_size = {{BITSIZE_S_data_ram_size-BITSIZE_Wsize{1'b0}}, data_size_next};
