always @(posedge clock) 
begin
  we <= we_next;
  addr <= addr_next;
  data <= data_next;
  data_size <= data_size_next;
  waiting <= waiting_next;
  start <= start_next;
  if(1RESET_VALUE)
  begin
    we <= 0;
