    waiting <= 0;
    start <= 0;
  end
end

always @(*)
begin
  we_next = we & HOLD & waiting & ~rdy;
  addr_next = addr & {BITSIZE_addr{HOLD & waiting & ~rdy}};
  data_next = data & {BITSIZE_Wdata{HOLD & waiting & ~rdy}};
  data_size_next = data_size & {BITSIZE_Wsize{HOLD & waiting & ~rdy}};
