  if(i_start_port)
  begin
    we_next = 1;
    addr_next = tgt_addr;
    data_next = 1;
    data_size_next = 1;
    waiting_next = ~rdy;
    start_next = rdy;
  end
end

localparam bytesize=((bitsize>>3)<<3) == bitsize ? (bitsize>>3) : ((bitsize>>3) + 1);
reg [bitsize-1:0] val;
wire [bitsize-1:0] val_next;
reg cyc, cyc_next, stb, stb_next, we, we_next, stall, ack, start;
reg [BITSIZE_addr_is-1:0] addr, addr_next;
reg [BITSIZE_dat_is-1:0] data, data_next;
reg [BITSIZE_sel_is-1:0] sel, sel_next;

if_utils #(index, bitsize) m_utils();

initial
begin
  val = 0;
  cyc = 0;
  cyc_next = 0;
  stb = 0;
  stb_next = 0;
  we = 0;
  we_next = 0;
  addr = 0;
  addr_next = 0;
  data = 0;
  data_next = 0;
  sel = 0;
  sel_next = 0;
  start = 0;
end

assign cyc_is = cyc_next;
assign stb_is = stb_next;
assign we_is = we_next;
assign addr_is = addr_next;
assign dat_is = data_next;
assign sel_is = sel_next;
assign stall = ~ack_os; // TODO: this should be stall_os
assign ack = ack_os;
assign start_port = start;

always @(posedge clock) 
begin
  automatic reg active_tx = cyc_next & ~ack;
  automatic reg wait_tx = active_tx & stall;
  val <= val_next;
  cyc <= active_tx;
  stb <= stb_next & wait_tx;
  we <= we_next & wait_tx;
  addr <= addr_next & {BITSIZE_addr_is{wait_tx}};
  data <= data_next & {BITSIZE_dat_is{wait_tx}};
  sel <= sel_next & {BITSIZE_sel_is{wait_tx}};
  start <= ack & cyc_next;
  if(setup_port)
  begin
    val <= m_utils.read();
  end
end

assign val_next = val;

always @(*)
begin
  cyc_next = cyc;
  stb_next = stb;
  we_next = we;
  addr_next = addr;
  data_next = data;
  sel_next = sel;
  if(i_start_port)
  begin
    cyc_next = 1;
    stb_next = 1;
    we_next = 1;
    addr_next = tgt_addr;
    data_next[bitsize-1:0] = val;
    sel_next = {bytesize{1'b1}};
  end
end

localparam bytesize=((bitsize>>3)<<3) == bitsize ? (bitsize>>3) : ((bitsize>>3) + 1);
reg cyc, cyc_next, stb, stb_next, stall, ack, done;
reg [BITSIZE_addr_is-1:0] addr, addr_next;

if_utils #(index, bitsize) m_utils();

initial
begin
  cyc = 0;
  cyc_next = 0;
  stb = 0;
  stb_next = 0;
  addr = 0;
  addr_next = 0;
  done = 0;
