  addr_next = addr;
  if(i_done_port)
  begin
    cyc_next = 1;
    stb_next = 1;
    addr_next = tgt_addr;
  end
end

localparam bytesize=1;
reg cyc, cyc_next, stb, stb_next, we, we_next, stall, ack, start;
reg [BITSIZE_addr_is-1:0] addr, addr_next;
reg [BITSIZE_dat_is-1:0] data, data_next;
reg [BITSIZE_sel_is-1:0] sel, sel_next;

initial
begin
  cyc = 0;
  cyc_next = 0;
  stb = 0;
  stb_next = 0;
  we = 0;
  we_next = 0;
  addr = 0;
  addr_next = 0;
  data = 0;
  data_next = 0;
  sel = 0;
  sel_next = 0;
  start = 0;
end

assign cyc_is = cyc_next;
assign stb_is = stb_next;
assign we_is = we_next;
assign addr_is = addr_next;
assign dat_is = data_next;
assign sel_is = sel_next;
assign stall = ~ack_os; // TODO: this should be stall_os
assign ack = ack_os;
assign start_port = start;

always @(posedge clock) 
begin
  automatic reg active_tx = cyc_next & ~ack;
  automatic reg wait_tx = active_tx & stall;
  cyc <= active_tx;
  stb <= stb_next & wait_tx;
  we <= we_next & wait_tx;
  addr <= addr_next & {BITSIZE_addr_is{wait_tx}};
  data <= data_next & {BITSIZE_dat_is{wait_tx}};
  sel <= sel_next & {BITSIZE_sel_is{wait_tx}};
  start <= ack & cyc_next;
end

always @(*)
begin
  cyc_next = cyc;
  stb_next = stb;
  we_next = we;
  addr_next = addr;
  data_next = data;
  sel_next = sel;
  if(i_start_port)
  begin
    cyc_next = 1;
    stb_next = 1;
    we_next = 1;
    addr_next = tgt_addr;
    data_next = 1;
    sel_next = {bytesize{1'b1}};
  end
end

if_utils #(index, BITSIZE_val_port) m_utils();
always @(posedge clock)
begin
  if(done_port)
  begin
    void'(m_utils.write(val_port));
  end
end

localparam CHANNELS_NUMBER=PORTSIZE_ce,
  BITSIZE_dq=BITSIZE_d > BITSIZE_q ? BITSIZE_d : BITSIZE_q,
  BITSIZE_item=BITSIZE_d+BITSIZE_address+BITSIZE_ce+BITSIZE_we,
  BITSIZE_chunk=BITSIZE_item*CHANNELS_NUMBER,
  OFFSET_ce=0,
  OFFSET_we=OFFSET_ce+BITSIZE_ce,
  OFFSET_address=OFFSET_we+BITSIZE_we,
  OFFSET_data=OFFSET_address+BITSIZE_address,
  LAST_READ_item=READ_DELAY > 1 ? READ_DELAY-2 : 0,
  LAST_READ_size=READ_DELAY > 1 ? READ_DELAY-1 : 1;
genvar i;

if_utils #(index, BITSIZE_dq) m_utils();

wire [BITSIZE_chunk-1:0] current;
reg [BITSIZE_chunk*WRITE_DELAY-1:0] queue = 0, queue_next = 0;
reg [CHANNELS_NUMBER*BITSIZE_q*LAST_READ_size-1:0] _q_next = 0;
reg [CHANNELS_NUMBER*BITSIZE_q*LAST_READ_size-1:0] _q = 0;

generate
  for(i = 0; i < CHANNELS_NUMBER; i = i + 1)
  begin
    assign current[BITSIZE_item*i+:BITSIZE_item] = {d[BITSIZE_d*i+:BITSIZE_d], address[BITSIZE_address*i+:BITSIZE_address], we[BITSIZE_we*i+:BITSIZE_we], ce[BITSIZE_ce*i+:BITSIZE_ce]};
    assign q[BITSIZE_q*i+:BITSIZE_q] = _q[LAST_READ_item*BITSIZE_q*CHANNELS_NUMBER+BITSIZE_q*i+:BITSIZE_q];
  end
endgenerate

generate
  if(WRITE_DELAY > 1)
  begin
    always @(posedge clock)
    begin
      if(setup_port)
      begin
        queue[BITSIZE_chunk*WRITE_DELAY-1:BITSIZE_chunk] <= 0;
        queue[BITSIZE_chunk-1:0] <= current;
      end
      else
      begin
        queue[BITSIZE_chunk*WRITE_DELAY-1:BITSIZE_chunk] <= queue_next[BITSIZE_chunk*WRITE_DELAY-1:BITSIZE_chunk];
        queue[BITSIZE_chunk-1:0] <= current;
      end
    end
    always @(*)
    begin
      queue_next[BITSIZE_chunk*WRITE_DELAY-1:BITSIZE_chunk] = queue[BITSIZE_chunk*(WRITE_DELAY-1)-1:0];
      queue_next[BITSIZE_chunk-1:0] = 0;
    end
  end
endgenerate

generate
  for(i = 0; i < CHANNELS_NUMBER; i = i + 1)
  begin : write_port
    if(WRITE_DELAY > 1)
    begin
      always @(posedge clock)
      begin
        automatic ptr_t address = queue_next[(WRITE_DELAY-1)*BITSIZE_chunk+BITSIZE_item*i+OFFSET_address+:BITSIZE_address];
        automatic reg [BITSIZE_d-1:0] data = queue_next[(WRITE_DELAY-1)*BITSIZE_chunk+BITSIZE_item*i+OFFSET_data+:BITSIZE_d];
        if(queue_next[(WRITE_DELAY-1)*BITSIZE_chunk+BITSIZE_item*i+OFFSET_ce+:BITSIZE_ce] === 1'b1
          && queue_next[(WRITE_DELAY-1)*BITSIZE_chunk+BITSIZE_item*i+OFFSET_we+:BITSIZE_we] === 1'b1)
        begin
          void'(m_utils.write_a(data, address));
        end
      end
    end
    else
    begin
      always @(posedge clock)
      begin
        automatic ptr_t address = current[BITSIZE_item*i+OFFSET_address+:BITSIZE_address];
        automatic reg [BITSIZE_d-1:0] data = current[BITSIZE_item*i+OFFSET_data+BITSIZE_d-1:BITSIZE_item*i+OFFSET_data];
        if(current[BITSIZE_item*i+OFFSET_ce+:BITSIZE_ce] === 1'b1 && current[BITSIZE_item*i+OFFSET_we+:BITSIZE_we] === 1'b1)
        begin
          void'(m_utils.write_a(data, address));
        end
      end
    end
  end
endgenerate

generate
  if(READ_DELAY > 2)
  begin : shift_output_queue1
    always @(*)
    begin
      _q_next[(READ_DELAY-1)*CHANNELS_NUMBER*BITSIZE_q-1:BITSIZE_q*CHANNELS_NUMBER] = _q[LAST_READ_item*CHANNELS_NUMBER*BITSIZE_q-1:0];
    end
  end
endgenerate
generate
  if(READ_DELAY > 2)
  begin : shift_output_queue2
    always @(posedge clock)
    begin
      _q[(READ_DELAY-1)*CHANNELS_NUMBER*BITSIZE_q-1:BITSIZE_q*CHANNELS_NUMBER] <= _q_next[(READ_DELAY-1)*CHANNELS_NUMBER*BITSIZE_q-1:BITSIZE_q*CHANNELS_NUMBER];
    end
  end
endgenerate
generate
  for(i = 0; i < CHANNELS_NUMBER; i = i + 1)
  begin : read_port
    if(READ_DELAY > 1)
    begin
      always @(posedge clock)
      begin
        if(current[BITSIZE_item*i+OFFSET_ce+:BITSIZE_ce] === 1'b1
            && current[BITSIZE_item*i+OFFSET_we+:BITSIZE_we] === 1'b0)
        begin
          automatic ptr_t address = current[BITSIZE_item*i+OFFSET_address+:BITSIZE_address];
          _q[BITSIZE_q*i+:BITSIZE_q] <= m_utils.read_a(address);
        end
        else
        begin
          _q[BITSIZE_q*i+:BITSIZE_q] <= 0;
        end
      end
    end
    else
    begin
      always @(*)
      begin
        if(current[BITSIZE_item*i+OFFSET_ce+:BITSIZE_ce] === 1'b1 && current[BITSIZE_item*i+OFFSET_we+:BITSIZE_we] === 1'b0)
        begin
          automatic ptr_t address = current[BITSIZE_item*i+OFFSET_address+:BITSIZE_address];
          _q[BITSIZE_q*i+:BITSIZE_q] = m_utils.read_a(address);
        end
      end
    end
  end
endgenerate

if_utils #(index, BITSIZE_dout) m_utils();

reg enable, enable_next;
reg _empty_n, _empty_n_next;
reg [BITSIZE_dout-1:0] val, val_next;

initial
begin
  enable = 0;
  _empty_n = 0;
  val = 0;
end

assign dout = val;
assign empty_n = _empty_n;

always @(posedge clock)
begin
  enable <= enable_next;
  _empty_n <= _empty_n_next;
  val <= val_next;
  if(setup_port)
  begin
    automatic int data = 0;
    val <= m_utils.read_i(data);
    _empty_n <= data > 0;
    enable <= 1'b1;
  end
  else if((enable_next | done_port) & read)
  begin
    automatic int data = 0;
    if(~_empty_n_next)
    begin
      $display("Too many read requests on interface %0d", index);
      $finish;
    end
    val <= m_utils.pop(data);
    _empty_n <= data > 0;
  end
end

always @(*)
begin
  enable_next = enable & ~done_port;
  _empty_n_next = _empty_n;
  val_next = val;
end

generate
  if(CHECK_ACK)
  begin
    reg ack_check, ack_check_next;
    initial ack_check = 0;
    assign ack_check_next = read | ack_check;
    always @(posedge clock)
    begin
      ack_check <= ack_check_next;
      if(setup_port)
      begin
        ack_check <= 0;
      end
      if(done_port & ~ack_check_next)
      begin
        $display("WARNING: Acknowledge signal never asserted on interface %0d.", index);
      end
    end
  end
endgenerate

if_utils #(index, BITSIZE_din) m_utils();

reg enable, enable_next;
reg _full_n, _full_n_next;

initial
begin
  enable = 0;
  _full_n = 0;
end

assign full_n = _full_n;

always @(posedge clock)
begin
  enable <= enable_next;
  _full_n <= _full_n_next;
  if(setup_port)
  begin
    automatic int data = 0;
    data = m_utils.state(4);
    _full_n <= data > 0;
    enable <= 1'b1;
  end
  if((enable_next | done_port) & write)
  begin
    automatic int data = 0;
    data = m_utils.push(din);
    _full_n <= data > 0;
    if(data < 0)
    begin
      $display("Too many write requests on interface %0d", index);
      $finish;
    end
  end
end

always @(*) 
begin
  enable_next = enable & ~done_port;
  _full_n_next = _full_n;
end
